import React from 'react';
import { useLanguage } from '@context/LanguageContext';
import { useGsapStagger } from '@hooks/useGsapScroll';
import { ShoppingCart, Laptop, Paintbrush, Languages, PenLine, FileSignature } from 'lucide-react';
import { devServices, translationServices } from '@data/services';
import ServiceCard from '@components/ui/ServiceCard';

const devIcons = {
  ecommerce: ShoppingCart,
  portfolio: Laptop,
  ui: Paintbrush,
};

const transIcons = {
  translation: Languages,
  editing: PenLine,
  writing: FileSignature,
};

const ServicesSection = () => {
  const { t } = useLanguage();
  const devRef = useGsapStagger({ stagger: 0.15 });
  const transRef = useGsapStagger({ stagger: 0.15 });

  return (
    <section id="services" className="py-24 relative">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 space-y-20">
        <div className="text-center max-w-3xl mx-auto space-y-4">
          <div className="section-kicker inline-flex">{t('dev_kicker')}</div>
          <h2 className="text-3xl sm:text-4xl font-bold text-text">{t('dev_title')}</h2>
          <p className="text-text-soft text-lg">{t('dev_text')}</p>
        </div>

        <div>
          <h3 className="text-xl font-bold text-text mb-8 text-center">{t('dev_services_title')}</h3>
          <div ref={devRef} className="grid md:grid-cols-3 gap-6">
            {devServices.map((service) => (
              <div key={service.id} className="stagger-card">
                <ServiceCard service={service} icon={devIcons[service.id]} />
              </div>
            ))}
          </div>
        </div>

        <div>
          <h3 className="text-xl font-bold text-text mb-8 text-center">{t('trans_services_title')}</h3>
          <div ref={transRef} className="grid md:grid-cols-3 gap-6">
            {translationServices.map((service) => (
              <div key={service.id} className="stagger-card">
                <ServiceCard service={service} icon={transIcons[service.id]} />
              </div>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
};

export default ServicesSection;
